import{_ as a,o as n,c as t,a2 as o}from"./chunks/framework.DtwafDNl.js";const h=JSON.parse('{"title":"Feature Overview","description":"","frontmatter":{},"headers":[],"relativePath":"features/index.md","filePath":"features/index.md"}'),i={name:"features/index.md"};function r(s,e,d,l,c,u){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="feature-overview" tabindex="-1">Feature Overview <a class="header-anchor" href="#feature-overview" aria-label="Permalink to &quot;Feature Overview&quot;">‚Äã</a></h1><p>Callytics is a self-hosted call center platform that combines telephony control, visual flow design, and operational tooling in one Linux-first deployment.</p><h2 id="core-call-control" tabindex="-1">Core call control <a class="header-anchor" href="#core-call-control" aria-label="Permalink to &quot;Core call control&quot;">‚Äã</a></h2><p>The platform includes a visual IVR flow builder with 13 node types, plus SIP extensions, SIP trunks, and inbound DID routing so teams can build and run real call paths without manual dialplan maintenance.</p><h2 id="agent-and-customer-routing" tabindex="-1">Agent and customer routing <a class="header-anchor" href="#agent-and-customer-routing" aria-label="Permalink to &quot;Agent and customer routing&quot;">‚Äã</a></h2><p>Queues, operators, hunt group strategies, conference rooms, and callback workflows are built in, covering core inbound handling and multi-destination routing patterns used by small and mid-size support teams.</p><h2 id="outbound-operations" tabindex="-1">Outbound operations <a class="header-anchor" href="#outbound-operations" aria-label="Permalink to &quot;Outbound operations&quot;">‚Äã</a></h2><p>Outbound campaigns support CSV import, scheduling, retry-aware contact handling, and sliding-window dialing to keep outbound traffic controlled and observable.</p><h2 id="media-and-voice-tooling" tabindex="-1">Media and voice tooling <a class="header-anchor" href="#media-and-voice-tooling" aria-label="Permalink to &quot;Media and voice tooling&quot;">‚Äã</a></h2><p>Audio upload, ffmpeg conversion, and offline Piper TTS are integrated into one prompt library, and call recordings are available for browser playback and direct download.</p><p>The browser softphone lets an operator register directly inside the dashboard, receive inbound calls, answer or reject them, and control mute or hangup without installing a separate SIP app.</p><h2 id="monitoring-and-diagnostics" tabindex="-1">Monitoring and diagnostics <a class="header-anchor" href="#monitoring-and-diagnostics" aria-label="Permalink to &quot;Monitoring and diagnostics&quot;">‚Äã</a></h2><p>Live dashboard views show active calls, queue state, and events, while call logs include execution traces and RTP quality scoring for post-call analysis.</p><p>Packet-level SIP Capture includes live stream inspection, ladder visualization, and <code>.pcap</code> export, and Diagnostics adds trunk tests, SIP registration visibility, and host resource metrics.</p><p>Asterisk Logs adds plain-English translation support so common runtime issues are easier to understand and resolve.</p><h2 id="security-connectivity-and-resilience" tabindex="-1">Security, connectivity, and resilience <a class="header-anchor" href="#security-connectivity-and-resilience" aria-label="Permalink to &quot;Security, connectivity, and resilience&quot;">‚Äã</a></h2><p>WireGuard VPN peer management enables secure remote endpoint onboarding with QR provisioning, and the SIP firewall provides abuse detection with auto-blocking and live feed visibility.</p><p>Backup and Restore provides manual and scheduled archives with retention controls, and the preflight wizard validates network and service readiness before production traffic.</p><h2 id="reuse-and-onboarding" tabindex="-1">Reuse and onboarding <a class="header-anchor" href="#reuse-and-onboarding" aria-label="Permalink to &quot;Reuse and onboarding&quot;">‚Äã</a></h2><p>Template import supports one-click IVR templates and JSON import paths to speed up initial setup and repeated deployment patterns.</p>',20)])])}const m=a(i,[["render",r]]);export{h as __pageData,m as default};
